import{_ as a,o as n,c as s,ag as o}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"推理设置","description":"","frontmatter":{},"headers":[],"relativePath":"docs/use/reasoning.md","filePath":"docs/use/reasoning.md","lastUpdated":null}'),t={name:"docs/use/reasoning.md"};function d(c,e,i,l,p,u){return n(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="推理设置" tabindex="-1">推理设置 <a class="header-anchor" href="#推理设置" aria-label="Permalink to &quot;推理设置&quot;">​</a></h1><p>本页面所有说明都应该在<code>OpenAI SDK</code>中使用。在<code>Claude</code> / <code>Gemini</code>原生 API 无效。</p><h2 id="claude" tabindex="-1">Claude <a class="header-anchor" href="#claude" aria-label="Permalink to &quot;Claude&quot;">​</a></h2><h3 id="claude-默认-tokens" tabindex="-1">Claude 默认 tokens <a class="header-anchor" href="#claude-默认-tokens" aria-label="Permalink to &quot;Claude 默认 tokens&quot;">​</a></h3><p>如果未指定<code>max_tokens</code>，我们会默认赋值<code>Claude</code>允许的最大 tokens 传入。 例如<code>claude-3-7</code>的最大 tokens 为<code>128000</code>。</p><h3 id="claude-3-7-模型开启-thinking" tabindex="-1">Claude 3.7 模型开启 thinking <a class="header-anchor" href="#claude-3-7-模型开启-thinking" aria-label="Permalink to &quot;Claude 3.7 模型开启 thinking&quot;">​</a></h3><p>在请求时，将模型名称后面添加 <code>#thinking</code> 可以开启 thinking 模式。 我们会自动将 <code>max_tokens</code> 的 80%作为<code>budget_tokens</code>传入给 Claude。</p><p>例如：</p><p>bash</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>curl -X POST https://api.maisi-ai.com/v1/chat/completions \\</span></span>
<span class="line"><span>  -H &quot;Content-Type: application/json&quot; \\</span></span>
<span class="line"><span>  -H &quot;Authorization: Bearer sk-proj-1234567890&quot; \\</span></span>
<span class="line"><span>  -d &#39;{</span></span>
<span class="line"><span>    &quot;model&quot;: &quot;claude-3-7-sonnet-20250219#thinking&quot;,</span></span>
<span class="line"><span>    &quot;messages&quot;: [{&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: &quot;你好&quot;}]</span></span>
<span class="line"><span>  }&#39;</span></span></code></pre></div><h3 id="自定义-claude-3-7-模型推理参数" tabindex="-1">自定义 Claude 3-7 模型推理参数 <a class="header-anchor" href="#自定义-claude-3-7-模型推理参数" aria-label="Permalink to &quot;自定义 Claude 3-7 模型推理参数&quot;">​</a></h3><p>您可以使用以下参数控制请求中的推理标记 reasoning：</p><p>json</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  &quot;model&quot;: &quot;claude-3-7-sonnet-2025021&quot;,</span></span>
<span class="line"><span>  &quot;messages&quot;: [],</span></span>
<span class="line"><span>  &quot;reasoning&quot;: {</span></span>
<span class="line"><span>    &quot;effort&quot;: &quot;high&quot;,</span><span> // 强度参数 (可选)</span></span>
<span class="line"><span>    &quot;max_tokens&quot;: 2000</span><span> // 推理最大tokens，目前特指budget_tokens (可选)</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre></div><h4 id="开启推理" tabindex="-1">开启推理 <a class="header-anchor" href="#开启推理" aria-label="Permalink to &quot;开启推理&quot;">​</a></h4><p>当您直接传入<code>&quot;reasoning&quot;: {}</code>时， 效果和<code>claude-3-7-sonnet-20250219#thinking</code>一致，不需要再更改模型名称。</p><h4 id="强度参数" tabindex="-1">强度参数 <a class="header-anchor" href="#强度参数" aria-label="Permalink to &quot;强度参数&quot;">​</a></h4><p><code>effort</code> 参数可以设置为 <code>high</code>、<code>medium</code> 或 <code>low</code>。</p><ul><li><code>high</code>：将分配<code>80%</code>的<code>max_tokens</code>作为<code>budget_tokens</code>。</li><li><code>medium</code>：将分配<code>50%</code>的<code>max_tokens</code>作为<code>budget_tokens</code>。</li><li><code>low</code>：将分配<code>20%</code>的<code>max_tokens</code>作为<code>budget_tokens</code>。</li></ul><h4 id="推理最大-tokens" tabindex="-1">推理最大 tokens <a class="header-anchor" href="#推理最大-tokens" aria-label="Permalink to &quot;推理最大 tokens&quot;">​</a></h4><p><code>reasoning.max_tokens</code> 参数可以设置为具体的数值，表示推理最大 tokens，目前特指 budget_tokens。</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><code>reasoning.max_tokens</code> 参数需要大于<code>max_tokens</code>,且不能低于<code>1024</code>。</p></div><h4 id="优先级" tabindex="-1">优先级 <a class="header-anchor" href="#优先级" aria-label="Permalink to &quot;优先级&quot;">​</a></h4><p>如果同时在<code>reasoning</code>传入<code>effort</code>和<code>max_tokens</code>，优先级如下：</p><ul><li><code>max_tokens</code> &gt; <code>effort</code></li></ul><h2 id="gemini" tabindex="-1">Gemini <a class="header-anchor" href="#gemini" aria-label="Permalink to &quot;Gemini&quot;">​</a></h2><h3 id="自定义-gemini-模型推理参数" tabindex="-1">自定义 Gemini 模型推理参数 <a class="header-anchor" href="#自定义-gemini-模型推理参数" aria-label="Permalink to &quot;自定义 Gemini 模型推理参数&quot;">​</a></h3><p><code>Gemini</code>的推理参数和<code>Claude</code>不一样， 在<code>gemini 2.5</code>中是默认开启推理的，如果需要关闭则需要传入<code>reasoning</code>参数。</p><p>json</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  &quot;model&quot;: &quot;gemini-2.5-flash-preview-04-17&quot;,</span></span>
<span class="line"><span>  &quot;messages&quot;: [],</span></span>
<span class="line"><span>  &quot;reasoning&quot;: {</span></span>
<span class="line"><span>    &quot;max_tokens&quot;: 2000</span><span> // 推理最大tokens，目前特指budget_tokens (可选)</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><code>reasoning.max_tokens</code> 为 0 时关闭推理。 或者只传入<code>&quot;reasoning&quot;: {}</code>时，默认关闭推理。</p></div>`,31)])])}const k=a(t,[["render",d]]);export{h as __pageData,k as default};
